import json
import os

class UserRepository:
    def __init__(self):
        # Using an in-memory dictionary for simple testing simulation
        self._users = {}

    def add_user(self, name, email):
        if email in self._users:
            return f"Error: User with email {email} already exists."
        self._users[email] = {"name": name, "email": email}
        return f"User {name} added successfully."

    def get_user(self, email):
        if email in self._users:
            # Return structured data or a representation thereof
            return self._users[email]
        return None # Indicate user not found

class UserStore:
    def __init__(self, db_path):
        self.db_path = db_path

    def save(self, users):
        # Users is expected to be a list of user dictionaries
        try:
            with open(self.db_path, 'w') as f:
                json.dump(users, f)
            return True
        except Exception as e:
            print(f"Error saving users: {e}")
            return False

    def load(self):
        if not os.path.exists(self.db_path) or os.stat(self.db_path).st_size == 0:
            return [] # Return empty list if file doesn't exist or is empty
        try:
            with open(self.db_path, 'r') as f:
                data = json.load(f)
                return data
        except json.JSONDecodeError:
            print("Error decoding JSON from user store.")
            return []
        except Exception as e:
            print(f"Error loading users: {e}")
            return []

class EmailService:
    def send_welcome_email(self, email):
        # Mocking actual email sending process
        print(f"[MOCK] Successfully sent welcome email to {email}.")
        return True

    def send_reset_email(self, email):
        # Mocking actual password reset link generation/sending
        print(f"[MOCK] Password reset instructions sent to {email}.")
        return True

